                    Diagnosis = "Hypertension",
                    TreatmentPlan = "Medication and lifestyle changes",
                    IsSensitive = false
                });
                _patientRecords.Add("P002", new PatientRecord
                {
                    PatientId = "P002",
                    FirstName = "Bob",
                    LastName = "Johnson",
                    DateOfBirth = new DateTime(1975, 1, 20),
                    Diagnosis = "Type 2 Diabetes",
                    TreatmentPlan = "Insulin therapy and diet management",
                    IsSensitive = true // This record is marked sensitive
