                Console.WriteLine($"Retrieved record for PatientId: {patientId}. IsSensitive: {record.IsSensitive}");
                return record;
            }
            Console.WriteLine($"PatientId: {patientId} not found.");
            return null;
        }

        public string SubmitPatientRecord(PatientRecord record)
        {
            IIdentity clientIdentity = OperationContext.Current.ServiceSecurityContext?.PrimaryIdentity;
            Console.WriteLine($"SubmitPatientRecord called by: {clientIdentity?.Name ?? "Anonymous"}");

            if (string.IsNullOrEmpty(record.PatientId))
            {
                return "Error: PatientId cannot be empty.";
            }

            if (_patientRecords.ContainsKey(record.PatientId))
            {
                _patientRecords[record.PatientId] = record;
                Console.WriteLine($"Updated record for PatientId: {record.PatientId}. IsSensitive: {record.IsSensitive}");
                return $"Patient record {record.PatientId} updated successfully.";
            }
            else
            {
                _patientRecords.Add(record.PatientId, record);
                Console.WriteLine($"Added new record for PatientId: {record.PatientId}. IsSensitive: {record.IsSensitive}");
                return $"Patient record {record.PatientId} added successfully.";
